import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "../styles/inicio.css";

function Inicio() {
  const navigate = useNavigate();

  // 🔹 estados del formulario
  const [documento, setDocumento] = useState("");
  const [password, setPassword] = useState("");
  const [codigo, setCodigo] = useState("");
  const [mostrarPass, setMostrarPass] = useState(false);

  // 🔹 navegación
  const irLogin = () => {
    navigate("/cuenta");
  };

  // 🔹 NUEVO: recuperar contraseña
  const irRecuperar = () => {
    navigate("/recuperar");
  };

  // 🔹 enviar formulario
  const manejarSubmit = (e) => {
    e.preventDefault();

    if (!documento || !password || !codigo) {
      alert("Completa todos los campos");
      return;
    }

    console.log("Datos enviados:", {
      documento,
      password,
      codigo,
    });

    navigate("/cuenta");
  };

  return (
    <div className="container">
      <form className="card" onSubmit={manejarSubmit}>
        <h1>Inicio</h1>
        <p className="subtitle">Bienvenido a nuestro menú de inicio.</p>

        {/* DOCUMENTO */}
        <label>Documento</label>
        <div className="input-group">
          <span className="icon">👤</span>
          <input
            type="text"
            placeholder="XXX.XXX.XXX"
            value={documento}
            onChange={(e) => setDocumento(e.target.value)}
          />
        </div>

        {/* PASSWORD */}
        <label>Password</label>
        <div className="input-group">
          <span className="icon">🔒</span>
          <input
            type={mostrarPass ? "text" : "password"}
            placeholder="********"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <span
            className="icon-right"
            onClick={() => setMostrarPass(!mostrarPass)}
            style={{ cursor: "pointer" }}
          >
            {mostrarPass ? "🙈" : "👁️"}
          </span>
        </div>

        {/* CODIGO */}
        <label>Código de verificación</label>
        <div className="input-group">
          <span className="icon">💬</span>
          <input
            type="text"
            placeholder="•••"
            value={codigo}
            onChange={(e) => setCodigo(e.target.value)}
          />
        </div>

        {/* BOTÓN */}
        <button type="submit" className="btn">
          Iniciar sesión
        </button>

        <p className="footer">
          © 2026 Financiero. Todos los derechos reservados. Política de seguridad
        </p>

        <p className="register">
          ¿No tienes cuenta?{" "}
          <span onClick={irLogin} style={{ cursor: "pointer" }}>
            Regístrate aquí.
          </span>
        </p>

        <p className="register">
          ¿Necesitas recuperar tu contraseña?{" "}
          <span onClick={irRecuperar} style={{ cursor: "pointer" }}>
            Cámbiala aquí.
          </span>
        </p>
      </form>
    </div>
  );
}

export default Inicio;
